mapper.select:
SELECT sr.id, sr.group_id, sr.id, sr.number, sr.counted_in_average, sr.arts_science, sr.subject_type, sr.school_id, sr.show_rule, s.id AS "subject.id", s.subject_number AS "subject.subjectNumber", s.subject_name AS "subject.subjectName", s.subject_english_name AS "subject.subjectEnglishName", s.unit AS "subject.unit", s.create_time AS "subject.createTime", s.update_time AS "subject.updateTime", s.school_id AS "subject.schoolId", s.scope AS "subject.scope" FROM subject_rel sr LEFT JOIN subject s ON sr.subject_id = s.id WHERE sr.deleted = 0 AND sr.school_id = #{req.schoolId}
AND sr.group_id = #{req.groupId}
AND s.subject_name LIKE CONCAT('%', #{req.name}, '%')
AND sr.counted_in_average = #{req.countedInAverage}
order by sr.number ASC
